const items = $input.all();
const results = [];

for (const item of items) {
  const binary = item.binary || {};
  const binaryKeys = Object.keys(binary);
  if (!binaryKeys.length) {
    throw new Error('No PDF binary payload was provided to the Processing Core workflow.');
  }

  const sourceBinary = {};
  let foundPdf = false;
  for (const key of binaryKeys) {
    const file = binary[key] || {};
    const fileName = String(file.fileName || '').toLowerCase();
    const mimeType = String(file.mimeType || '').toLowerCase();
    if (mimeType === 'application/pdf' || fileName.endsWith('.pdf')) {
      sourceBinary.pdf = binary[key];
      foundPdf = true;
      break;
    }
  }
  if (!foundPdf) {
    sourceBinary.pdf = binary[binaryKeys[0]];
  }

  const source = item.json || {};
  results.push({
    json: {
      source_filename: source.source_filename || sourceBinary.pdf.fileName || 'unknown.pdf',
      ingestion_channel: source.ingestion_channel || 'unknown',
      received_date: source.received_date || null,
      document_hash: null,
      duplicate_mode: String(source.duplicate_mode || 'overwrite').toLowerCase(),
      persist_result: source.persist_result !== false,
      persistence_mode: source.persistence_mode === 'none' ? 'none' : 'postgres',
      pdf_base64_data: source.pdf_base64_data || null,
    },
    binary: sourceBinary,
  });
}
return results;

const items = $input.all();
const normalizedItems = $('Normalize Intake Payload').all();

const results = [];
for (let index = 0; index < items.length; index++) {
  const item = items[index];
  const source = item.json || {};
  const normalizedItem = normalizedItems[index] || normalizedItems[0] || {};
  const sourceBinary = (item.binary && Object.keys(item.binary).length > 0)
    ? item.binary
    : (normalizedItem.binary || {});

  const pdfSizeBytes = sourceBinary.pdf?.bytes || sourceBinary.pdf?.fileSize || null;
  const pdfMimeType = sourceBinary.pdf?.mimeType || 'application/pdf';

  results.push({
    json: {
      received_date: source.received_date || null,
      document_type: null,             // expose | other  (AI classification)
      project_name: null,
      asset_class: null,               // Wohnen | Office | Retail | Gewerbe | Health Care | Logistik | Sicherheit | Bildung
      provider: null,
      provider_contact: {
        name: null,
        company: null,
        phone: null,
        email: null,
      },
      owner: null,
      address: {
        country: 'Austria',
        state: null,                   // Bundesland (derived from PLZ + city)
        postal_code: null,
        city: null,
        street: null,
        house_number: null,
      },
      areas: {
        usable_area_m2: null,
        realizable_usable_area_m2: null,  // Realisierbare Nutzfläche
        gross_floor_area_m2: null,         // BFG (Bruttoflächengesamt)
        plot_area_m2: null,
        rented_area_m2: null,              // Vermietete Flächen m²
        vacancy_area_m2: null,             // Leerstand m²
      },
      financials: {
        target_rent_pa_eur: null,
        actual_rent_pa_eur: null,
        asking_price_eur: null,
        price_per_m2_usable_area: null,
        price_per_m2_land: null,
        rental_units_count: null,          // Anzahl Mieteinnahmen
        broker_commission: null,           // Maklerprovision (string, e.g. "3% zzgl. USt")
        bidding_process: null,             // Bieterverfahren (boolean)
      },
      property: {
        property_type: null,
        object_category: null,             // Objekttyp: Bestand | Grundstück | Projekt
        ownership_type: null,
        construction_year: null,
        heritage_protection: null,
        vacancy: null,
        parking_spaces: null,
        land_register: null,               // Grundbuchsdaten
        planned_use: null,                 // Nutzung (geplant)
        zoning: null,                      // Widmung
        building_class: null,              // Bauklasse
      },
      returns: {
        gross_initial_yield_actual: null,
        gross_initial_yield_target: null,
      },
      notes: null,
      location_enrichment: {
        latitude: null,
        longitude: null,
        map_url: null,                     // OpenStreetMap link generated from lat/lon
        aerial_image_url: null,
        location_description: null,
        public_transport_access: null,
        distance_city_center_min: null,
        distance_train_station_min: null,
        distance_airport_min: null,
        infrastructure: [],
      },
      market_context: {
        potential_revenue: null,
        demographics: {
          population_development: null,
          purchasing_power: null,
        },
      },
      processing_metadata: {
        document_id: source.document_hash || null,
        source_filename: source.source_filename || null,
        ingestion_channel: source.ingestion_channel || null,
        processed_at: null,
        status: 'pending',
        validation_errors: [],
      },
        _runtime: {
        duplicate_mode: source.duplicate_mode || 'overwrite',
        persist_result: source.persist_result !== false,
        persistence_mode: source.persistence_mode || 'postgres',
        duplicate_lookup_requested: source.persist_result !== false && source.persistence_mode !== 'none' ? 1 : null,
        duplicate_found: false,
        reuse_existing_marker: null,
        reused_payload: null,
        duplicate_lookup_error: null,
        extracted_text: null,
        expose_location_description: null,
        ai_error: null,
        enrichment_failed: false,
        persistence_error: null,
        persist_result_marker: null,
        document_hash: source.document_hash || null,
        source_filename: source.source_filename || null,
        pdf_base64: source.pdf_base64_data || null,
        pdf_size_bytes: pdfSizeBytes,
        pdf_mime_type: pdfMimeType,
      },
    },
    binary: sourceBinary,  // Binary stripped here: hash already computed, pdf.js extraction handled separately
  });
}
return results;

const baseItem = $('Initialize Extraction Context').first();
const base = JSON.parse(JSON.stringify(baseItem.json || {}));
const binary = baseItem.binary || {};
const lookupItem = $input.first();
const lookup = lookupItem ? (lookupItem.json || {}) : {};
const runtime = base._runtime && typeof base._runtime === 'object' ? base._runtime : {};
const lookupPayload = lookup.payload_jsonb ?? lookup.json_payload ?? null;
const lookupMatched =
  lookup.found === true ||
  lookup.id != null ||
  lookup.pdf_hash != null ||
  lookupPayload != null;

if (lookup.error) {
  runtime.duplicate_lookup_error = lookup.error.message || String(lookup.error);
}

if (runtime.persist_result && runtime.persistence_mode === 'postgres' && lookupMatched) {
  runtime.duplicate_found = true;
}

if (runtime.persist_result && runtime.persistence_mode === 'postgres' && runtime.duplicate_mode === 'skip' && lookupMatched && lookupPayload) {
  let reusedPayload = lookupPayload;
  if (typeof reusedPayload === 'string') {
    reusedPayload = JSON.parse(reusedPayload);
  }
  if (!reusedPayload.processing_metadata || typeof reusedPayload.processing_metadata !== 'object') {
    reusedPayload.processing_metadata = {};
  }
  if (!Array.isArray(reusedPayload.processing_metadata.validation_errors)) {
    reusedPayload.processing_metadata.validation_errors = [];
  }
  reusedPayload.processing_metadata.document_id = reusedPayload.processing_metadata.document_id || lookup.pdf_hash || base.processing_metadata?.document_id || null;
  reusedPayload.processing_metadata.source_filename = reusedPayload.processing_metadata.source_filename || lookup.pdf_filename || base.processing_metadata?.source_filename || null;
  reusedPayload.processing_metadata.status = 'duplicate_skipped';
  runtime.reuse_existing_marker = 1;
  runtime.duplicate_skip_applied = true;
  runtime.reused_payload = reusedPayload;
}

base._runtime = runtime;
return [{ json: base, binary }];

