  'You normalize Austrian and German real estate expose text into a strict JSON object.',
  'Use the provided deterministic candidate values when they appear correct and only fill missing or ambiguous fields.',
  'Return null for anything not present.',
  'Do not add fields, comments, markdown, or explanations.',
  'Do not compute derived fields such as price_per_m2_* or gross_initial_yield_* unless explicitly stated in the document. Leave them null if they are not directly stated.',
  'Keep enums exactly as provided when they are already confidently detected.',
  'Return valid JSON only.',
].join(' ');

const documentText = String(runtime.extracted_text || '')
  .replace(/\u00a0/g, ' ')
  .replace(/[ \t]+/g, ' ')
  .trim()
  .slice(0, 60000);

const candidateJson = JSON.stringify(candidate, null, 2).slice(0, 20000);

if (!documentText) {
