const priorPayload = $('Parse Expose Deterministically').first().json || {};
const runtime = priorPayload._runtime || {};
const response = $input.first().json || {};

let parsed = {};
let aiError = response.error?.message || response.error || null;

// Extract text from Responses API output
let rawText = '';
for (const out of response.output || []) {
  for (const c of out.content || []) {
    if (c.type === 'output_text' && c.text) rawText = c.text;
    if (!parsed && c.type === 'output_json' && c.json) parsed = c.json;
  }
}

if (!parsed || !Object.keys(parsed).length) {
  try {
    const cleaned = rawText
      .replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
    parsed = JSON.parse(cleaned);
  } catch(e) {
    aiError = (aiError ? aiError + ' | ' : '') + 'JSON parse: ' + e.message + ' | raw: ' + rawText.slice(0, 200);
    parsed = {};
  }
}

// Map German Adresse → English address for Location Enrichment sub-workflow
if (parsed.Adresse && typeof parsed.Adresse === 'object') {
  parsed.address = {
    street: parsed.Adresse['Stra\u00dfe'] || null,
    house_number: parsed.Adresse.Hausnummer || null,
    postal_code: parsed.Adresse.PLZ || null,
    city: parsed.Adresse.Stadt || null,
    country: parsed.Adresse.Land || 'Austria',
  };
}

return [{
  json: {
    ...parsed,
    _runtime: { ...runtime, ai_error: aiError },
  },
}];

const payload = JSON.parse(JSON.stringify($input.first().json || {}));
const runtime = payload._runtime && typeof payload._runtime === 'object' ? payload._runtime : {};
const le = payload.location_enrichment || {};
const infra = Array.isArray(runtime.infrastructure) ? runtime.infrastructure : [];
const trainStation = runtime.nearest_train_station || null;
const airport = runtime.nearest_airport || null;

// Haversine distance in meters
function haversineM(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return Math.round(R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a)));
}

// Known Austrian city centers (for Ortsmitte)
const CITY_CENTERS = {
  'Wien': { name: 'Stephansplatz', lat: 48.2085, lon: 16.3726 },
  'Graz': { name: 'Hauptplatz', lat: 47.0707, lon: 15.4395 },
  'Salzburg': { name: 'Mozartplatz', lat: 47.7981, lon: 13.0462 },
  'Innsbruck': { name: 'Maria-Theresien-Stra\u00dfe', lat: 47.2682, lon: 11.3923 },
  'Linz': { name: 'Hauptplatz', lat: 48.3059, lon: 14.2862 },
  'Klagenfurt': { name: 'Neuer Platz', lat: 46.6228, lon: 14.3098 },
  'Villach': { name: 'Hauptplatz', lat: 46.6110, lon: 13.8458 },
  'Wels': { name: 'Stadtplatz', lat: 48.1579, lon: 14.0286 },
  'St. P\u00f6lten': { name: 'Rathausplatz', lat: 48.2040, lon: 15.6229 },
};

const originLat = le.latitude;
const originLon = le.longitude;
const hasCoords = originLat != null && !isNaN(originLat) && originLon != null && !isNaN(originLon);
const city = payload.Adresse?.Stadt || '';

// Train station
let trainName = '', trainDist = '';
if (trainStation?.name) {
  trainName = trainStation.name;
  if (hasCoords && trainStation.latitude && trainStation.longitude) {
    trainDist = 'ca. ' + haversineM(originLat, originLon, trainStation.latitude, trainStation.longitude) + ' m';
  }
}

// Airport
let airportName = '', airportDist = '';
if (airport?.name) {
  airportName = airport.name;
  if (hasCoords && airport.latitude && airport.longitude) {
    airportDist = 'ca. ' + haversineM(originLat, originLon, airport.latitude, airport.longitude) + ' m';
  }
}

// City center
let ortsName = '', ortsDist = '';
const cityCenter = city ? (CITY_CENTERS[city] || null) : null;
if (cityCenter && hasCoords) {
  ortsName = cityCenter.name;
  ortsDist = 'ca. ' + haversineM(originLat, originLon, cityCenter.lat, cityCenter.lon) + ' m';
}

// Infrastructure by category
const byCategory = (cat) => infra.filter(i => i.category === cat).sort((a,b) => (a.distance_m||Infinity)-(b.distance_m||Infinity));
const nearestEdu = byCategory('education')[0] || null;
const nearestHealth = byCategory('healthcare')[0] || null;
const nearestRetail = byCategory('retail')[0] || null;

// Build Makrolage text
const makroLines = [];
if (trainName) makroLines.push('N\u00e4chster Bahnhof: ' + trainDist + (trainName ? ' (' + trainName + ')' : ''));
if (airportName) makroLines.push('Flughafen [' + airportName + ']: ' + airportDist);
if (nearestEdu) makroLines.push('N\u00e4chste Bildungseinrichtung: ca. ' + nearestEdu.distance_m + ' m' + (nearestEdu.name ? ' (' + nearestEdu.name + ')' : ''));

// Only overwrite Lagebeschreibung fields if enrichment yielded data
if (hasCoords || trainName || airportName) {
  payload.Lagebeschreibung = payload.Lagebeschreibung || {};

  if (makroLines.length > 0) {
    payload.Lagebeschreibung.Makrolage = makroLines.join('\n');
  }

  const entf = payload.Lagebeschreibung.Entfernungen || {};
  if (trainName) entf.Naechster_Bahnhof = { Bezeichnung: trainName, Entfernung: trainDist };
  if (airportName) entf.Flughafen = { Bezeichnung: airportName, Entfernung: airportDist };
  if (ortsName) entf.Ortsmitte = { Bezeichnung: ortsName, Entfernung: ortsDist };
  payload.Lagebeschreibung.Entfernungen = entf;

  const mikro = payload.Lagebeschreibung.Mikrolage_und_Infrastruktur || {};
  if (nearestEdu) mikro.Bildungsbauten = nearestEdu.name + (nearestEdu.distance_m ? ' (ca. ' + nearestEdu.distance_m + ' m)' : '');
  if (nearestHealth) mikro.Medizinische_Versorgung = nearestHealth.name + (nearestHealth.distance_m ? ' (ca. ' + nearestHealth.distance_m + ' m)' : '');
  if (nearestRetail) mikro['Einkaufsm\u00f6glichkeiten'] = nearestRetail.name + (nearestRetail.distance_m ? ' (ca. ' + nearestRetail.distance_m + ' m)' : '');
  payload.Lagebeschreibung.Mikrolage_und_Infrastruktur = mikro;
}

// Set routing marker for persistence sub-workflow
payload._runtime = {
  ...runtime,
  persist_result_marker: runtime.persist_result && runtime.persistence_mode === 'postgres' ? 1 : null,
};

return [{ json: payload }];

const item = $input.first() || {};
